PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE weights (id integer NOT NULL PRIMARY KEY AUTOINCREMENT, name text NOT NULL);
CREATE TABLE twistlocks (id integer NOT NULL PRIMARY KEY AUTOINCREMENT, name text NOT NULL);
CREATE TABLE turnbuckles (id integer NOT NULL PRIMARY KEY AUTOINCREMENT, name text NOT NULL);
CREATE TABLE stackers (id integer NOT NULL PRIMARY KEY AUTOINCREMENT, name text NOT NULL);
CREATE TABLE nuts (id integer NOT NULL PRIMARY KEY AUTOINCREMENT, name text NOT NULL);
CREATE TABLE lashing_patterns (id integer NOT NULL PRIMARY KEY AUTOINCREMENT, name text NOT NULL);
CREATE TABLE lashing_bridges (id integer NOT NULL PRIMARY KEY AUTOINCREMENT, name text NOT NULL);
CREATE TABLE gear_qualities (id integer NOT NULL PRIMARY KEY AUTOINCREMENT, name text NOT NULL);
CREATE TABLE extensions (id integer NOT NULL PRIMARY KEY AUTOINCREMENT, name text NOT NULL);
CREATE TABLE bars (id integer NOT NULL PRIMARY KEY AUTOINCREMENT, name text NOT NULL);
CREATE TABLE vessels (id integer NOT NULL PRIMARY KEY AUTOINCREMENT, imo integer NOT NULL UNIQUE, name varchar (64) NOT NULL, built integer DEFAULT NULL, teu integer DEFAULT NULL, bays integer DEFAULT NULL, width integer DEFAULT NULL, former_names text DEFAULT NULL, deck_lashing_range text DEFAULT NULL, deck_lashing_pattern_id integer DEFAULT NULL REFERENCES lashing_patterns (id), obstructions integer DEFAULT NULL, lashing_bridges_id integer DEFAULT NULL REFERENCES lashing_bridges (id), lashing_bridge_range text DEFAULT NULL, stretch_bays integer DEFAULT NULL, lashing_pattern_id integer DEFAULT NULL REFERENCES lashing_patterns (id), end_lashing_pattern_id integer DEFAULT NULL REFERENCES lashing_patterns (id), horizontal_lashing integer DEFAULT NULL, lashing_notes text DEFAULT NULL, bars_id integer DEFAULT NULL REFERENCES bars (id), bar_weight_id integer DEFAULT NULL REFERENCES weights (id), extensions_id integer DEFAULT NULL REFERENCES extensions (id), turnbuckles_id integer DEFAULT NULL REFERENCES turnbuckles (id), turnbuckle_quality_id integer DEFAULT NULL REFERENCES gear_qualities (id), turnbuckle_weight_id integer DEFAULT NULL REFERENCES weights (id), turnbuckle_notes text DEFAULT NULL, swivel_nut integer DEFAULT NULL, nuts_id integer DEFAULT NULL REFERENCES nuts (id), wd40 integer DEFAULT NULL, twistlocks_id integer DEFAULT NULL REFERENCES twistlocks (id), bad_twistlocks integer DEFAULT NULL, semi_automatic_lid_twistlocks integer DEFAULT NULL, stackers_id integer DEFAULT NULL REFERENCES stackers (id), two_houses integer DEFAULT NULL, notes text DEFAULT NULL);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_name ON vessels (name);
COMMIT;
